原题链接

首先需要判断连通分量，即判断有环无环，用并查集的速度是最快的
并查集：
初始化：p[i]=i，每个节点是自己的老大；
找根：find(x)，递归找老大 + 路径压缩；
合并：不同老大才合并，连通块数减一；
判连通：看最终连通块数是否为 1。





int find(int x){	return (x == p[x]) ? x : p[x] = find(p[x]);}//初始化并查集：每个结点的父节点是自身for(int i = 1; i &lt;= n; i++) p[i] = i;//并查集合并if(find(a) != find(b)){    p[find(a)] = p[find(b)];    cnt--;} 


dfs找最深的根

#include&lt;iostream&gt;#include&lt;algorithm&gt;#include&lt;vector&gt;#include&lt;cstdio&gt;#include&lt;string&gt;#include&lt;cstring&gt;#include&lt;cctype&gt;#include&lt;cmath&gt;#include&lt;map&gt;#include&lt;set&gt;#include&lt;climits&gt;#include &lt;unordered_map&gt;#include &lt;queue&gt;using namespace std;const int N = 10010;vector&lt;int&gt; v[N]; //邻接表： v[t]存储节点t的所有邻接节点int p[N]; // 并查集父节点数组 int n;set&lt;int&gt; ans;int find(int x){	return (x == p[x]) ? x : p[x] = find(p[x]);}int dfs(int u, int f){	int d = 0; 	for(int i = 0; i &lt; v[u].size(); i++)	{		int e = v[u][i];		if(f == e) continue;		d = max(d, dfs(e, u) +1);	}	return d;}int main(){	cin &gt;&gt; n;	int cnt = n, maxd = -1;	//初始化并查集：每个结点的父节点是自身	for(int i = 1; i &lt;= n; i++) p[i] = i;		for(int i = 0; i &lt; n - 1; i++)	{		int a, b; cin &gt;&gt; a &gt;&gt; b;		v[a].push_back(b);		v[b].push_back(a);				//并查集合并		if(find(a) != find(b))		{			p[find(a)] = p[find(b)];			cnt--;		} 	}		if(cnt &gt; 1) printf("Error: %d components",cnt);	else	{		for(int i = 1; i &lt;=n; i++)		{			int deep = dfs(i, -1);			if(deep &gt; maxd)			{				ans.clear();				maxd = deep;				ans.insert(i);			}			else if(deep == maxd)			{				ans.insert(i);			}		}	}	for(auto it : ans) cout &lt;&lt; it &lt;&lt; endl;	return 0; }
